import { chromium } from "playwright";

const browser = await chromium.launch({ headless: true });
const ctx = await browser.newContext({ viewport: { width: 1280, height: 800 } });
const page = await ctx.newPage();

const errors = [];
const consoleLog = [];
page.on("pageerror", (err) => errors.push(`PAGE ERROR: ${err.message}\n${err.stack}`));
page.on("console", (msg) => {
  consoleLog.push(`${msg.type()}: ${msg.text()}`);
  if (msg.type() === "error") errors.push(`CONSOLE ERROR: ${msg.text()}`);
});
page.on("requestfailed", (req) => errors.push(`REQUEST FAILED: ${req.url()} ${req.failure()?.errorText}`));

await page.goto("http://localhost:4173/", { waitUntil: "load", timeout: 30000 });

// Wait for loading to finish.
await page.waitForFunction(
  () => !document.getElementById("loading") || document.getElementById("loading").style.display === "none",
  { timeout: 30000 },
);

// Wait a bit for first frame.
await page.waitForTimeout(2000);

// Take screenshot.
await page.screenshot({ path: "/tmp/scene1.png", fullPage: false });

// Click on the scene to verify interaction.
await page.mouse.click(640, 400);
await page.waitForTimeout(500);

// Check what's loaded.
const stats = await page.evaluate(() => {
  return {
    uiShown: document.getElementById("ui-shown")?.textContent,
    uiDate: document.getElementById("ui-date")?.textContent,
    canvasW: document.getElementById("scene")?.clientWidth,
    canvasH: document.getElementById("scene")?.clientHeight,
  };
});

console.log("=== STATS ===");
console.log(JSON.stringify(stats, null, 2));
console.log("=== ERRORS ===");
errors.forEach((e) => console.log(e));
console.log("=== CONSOLE LOG (last 20) ===");
consoleLog.slice(-20).forEach((l) => console.log(l));

await browser.close();
process.exit(errors.length > 0 ? 1 : 0);
