cat > /tmp/debug-shaders.py << 'EOF'
import asyncio, sys
from playwright.async_api import async_playwright

async def main():
    console = []
    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=True, args=["--use-gl=swiftshader", "--enable-webgl"])
        page = await (await browser.new_context(viewport={"width": 1280, "height": 800})).new_page()
        page.on("console", lambda msg: console.append(f"{msg.type}: {msg.text}"))
        page.on("pageerror", lambda err: console.append(f"PAGEERR: {err.message}"))
        await page.goto("http://127.0.0.1:5002/", wait_until="load", timeout=30000)
        await page.wait_for_timeout(3000)
        # Get shader log
        info = await page.evaluate("""() => {
            const out = [];
            // Walk the scene and grab material info
            const can = document.querySelector('#scene');
            // Three.js doesn't expose internals from canvas directly; we can use any
            // global module objects if any.
            out.push('canvas size: ' + can.width + 'x' + can.height);
            out.push('client: ' + can.clientWidth + 'x' + can.clientHeight);
            return out.join('\\n');
        }""")
        print("INFO:", info)
        print("\n=== CONSOLE (all) ===")
        for c in console[:60]:
            print(c)
        await browser.close()

asyncio.run(main())
